// src/pages/HomeScreen.js
import React, { useMemo, useState } from "react";
import {
  SafeAreaView,
  View,
  Text,
  StyleSheet,
  Image,
  TextInput,
  TouchableOpacity,
  ScrollView,
  Platform,
  useWindowDimensions,
} from "react-native";

const nalicoreLogo = require("../../assets/nalicore_logo.png");

export default function HomeScreen() {
  const { width } = useWindowDimensions();

  // Layout rules:
  // - Always keep input + resolve on same row (like your mock)
  // - Only stack on extremely tiny screens
  const stackSearch = width < 340;

  // Centered container on web/tablet
  const maxWidth = width >= 1024 ? 520 : width >= 768 ? 520 : "100%";

  const [query, setQuery] = useState(
    "Total borne 10 entre\nenfant noir chez le boss"
  );

  const resolved = useMemo(
    () => ({
      quartier: "Odza",
      secteur: "Borne 10",
      sousSecteur: "Total borne 10",
      entree: "Enfant Noir",
      lieu: "Chez le Boss",
      banoc: "Q5TCL",
      latitude: 3.7862,
      longitude: 111.53045,
    }),
    []
  );

  const onResolve = () => console.log("Resolve:", query);
  const onNavigate = () =>
    console.log("Navigate:", resolved.latitude, resolved.longitude);

  return (
    <SafeAreaView style={styles.safe}>
      <ScrollView contentContainerStyle={styles.scroll} showsVerticalScrollIndicator={false}>
        <View style={[styles.container, { maxWidth }]}>
          {/* Header */}
          <View style={styles.header}>
            <Image source={nalicoreLogo} style={styles.logo} resizeMode="contain" />
            <Text style={styles.tagline}>
              Natural Address{"\n"}Location{"\n"}Infrastructure
            </Text>
          </View>

          {/* Search + Resolve */}
          <View style={[styles.searchRow, { flexDirection: stackSearch ? "column" : "row" }]}>
            <View style={styles.searchInputWrap}>
              <Text style={styles.searchIcon}>⌕</Text>
              <TextInput
                value={query}
                onChangeText={setQuery}
                style={styles.searchInput}
                placeholder="Type an address…"
                placeholderTextColor="rgba(15,23,42,0.45)"
                multiline
                numberOfLines={2}
                scrollEnabled={false}
                textAlignVertical="center"
              />
            </View>

            <TouchableOpacity
              activeOpacity={0.9}
              style={[styles.resolveBtn, stackSearch && { width: "100%" }]}
              onPress={onResolve}
            >
              <Text style={styles.resolveText}>Resolve</Text>
            </TouchableOpacity>
          </View>

          {/* Card */}
          <View style={styles.card}>
            <Text style={styles.cardTitle}>Resolved Address</Text>

            <Row label="Quartier:" value={resolved.quartier} />
            <Row label="Secteur:" value={resolved.secteur} />
            <Row label="Sous-secteur:" value={resolved.sousSecteur} />
            <Row label="Entrée:" value={resolved.entree} />
            <Row label="Lieu:" value={resolved.lieu} />

            <View style={styles.row}>
              <Text style={styles.label}>BANOC:</Text>
              <View style={styles.banocPill}>
                <Text style={styles.banocText}>{resolved.banoc}</Text>
              </View>
            </View>

            {/* IMPORTANT: single-value lat/lng */}
            <Row label="Latitude:" value={Number(resolved.latitude).toFixed(5)} />
            <Row label="Longitude:" value={Number(resolved.longitude).toFixed(5)} />

            <TouchableOpacity activeOpacity={0.9} style={styles.navBtn} onPress={onNavigate}>
              <Text style={styles.navIcon}>⌖</Text>
              <Text style={styles.navText}>Navigate to Location</Text>
            </TouchableOpacity>
          </View>

          <View style={{ height: 220 }} />
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

function Row({ label, value }) {
  return (
    <View style={styles.row}>
      <Text style={styles.label} numberOfLines={1}>
        {label}
      </Text>
      <Text style={styles.value} numberOfLines={1} ellipsizeMode="tail">
        {value}
      </Text>
    </View>
  );
}

const styles = StyleSheet.create({
  safe: { flex: 1, backgroundColor: "#E9ECF6" },
  scroll: { paddingBottom: 28 },

  // Keep the “phone-like” centered column on web like your mock image
  container: {
    width: "100%",
    alignSelf: "center",
    paddingTop: 18,
    paddingHorizontal: 18,
  },

  header: {
    flexDirection: "row",
    alignItems: "flex-start",
    justifyContent: "space-between",
    marginBottom: 16,
  },
  logo: { width: 185, height: 50 },
  tagline: {
    textAlign: "right",
    color: "rgba(15,23,42,0.62)",
    fontSize: 16,
    fontWeight: "700",
    lineHeight: 22,
  },

  searchRow: {
    alignItems: "stretch",
    gap: 12,
    marginBottom: 18,
  },
  searchInputWrap: {
    flex: 1,
    minHeight: 66,
    borderRadius: 18,
    backgroundColor: "rgba(255,255,255,0.70)",
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    paddingLeft: 44,
    paddingRight: 12,
    justifyContent: "center",
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.06,
        shadowRadius: 14,
        shadowOffset: { width: 0, height: 10 },
      },
      android: { elevation: 2 },
    }),
  },
  searchIcon: {
    position: "absolute",
    left: 16,
    top: 22,
    fontSize: 18,
    color: "rgba(15,23,42,0.45)",
  },
  searchInput: {
    fontSize: 20,
    fontWeight: "800",
    color: "#0F172A",
    lineHeight: 26,
    paddingVertical: 8,
  },

  resolveBtn: {
    width: 150,
    minHeight: 66,
    borderRadius: 18,
    backgroundColor: "#2E59B7",
    alignItems: "center",
    justifyContent: "center",
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.10,
        shadowRadius: 16,
        shadowOffset: { width: 0, height: 12 },
      },
      android: { elevation: 4 },
    }),
  },
  resolveText: {
    color: "#FFFFFF",
    fontSize: 20,
    fontWeight: "900",
  },

  card: {
    borderRadius: 22,
    padding: 18,
    backgroundColor: "rgba(255,255,255,0.70)",
    borderWidth: 1,
    borderColor: "rgba(15,23,42,0.08)",
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.08,
        shadowRadius: 18,
        shadowOffset: { width: 0, height: 14 },
      },
      android: { elevation: 3 },
    }),
  },
  cardTitle: {
    fontSize: 28,
    fontWeight: "900",
    color: "#0F172A",
    marginBottom: 14,
  },

  row: {
    flexDirection: "row",
    alignItems: "center",
    marginBottom: 12,
  },
  label: {
    width: 140,            // prevents “Sous- / secteur” wrapping
    fontSize: 18,
    fontWeight: "800",
    color: "rgba(15,23,42,0.45)",
  },
  value: {
    flex: 1,
    fontSize: 20,
    fontWeight: "900",
    color: "#0F172A",
    textAlign: "left",
  },

  banocPill: {
    borderRadius: 14,
    paddingHorizontal: 14,
    paddingVertical: 8,
    backgroundColor: "rgba(46,89,183,0.12)",
    borderWidth: 1,
    borderColor: "rgba(46,89,183,0.20)",
  },
  banocText: {
    color: "#2E59B7",
    fontSize: 18,
    fontWeight: "900",
    letterSpacing: 1,
  },

  navBtn: {
    marginTop: 16,
    height: 74,
    borderRadius: 22,
    backgroundColor: "#2E59B7",
    alignItems: "center",
    justifyContent: "center",
    flexDirection: "row",
    gap: 10,
    ...Platform.select({
      ios: {
        shadowColor: "#000",
        shadowOpacity: 0.12,
        shadowRadius: 18,
        shadowOffset: { width: 0, height: 14 },
      },
      android: { elevation: 5 },
    }),
  },
  navIcon: { color: "#FFFFFF", fontSize: 18 },
  navText: { color: "#FFFFFF", fontSize: 22, fontWeight: "900" },
});
